sys_script_include.script:
const ContactMainListWidgetHelper = Class.create();

ContactMainListWidgetHelper.CONTACT_MAIN_LIST_BREADCRUMB = [
    ...Constants.HOME_BREADCRUMB,
    { title: "Contacts", link: "?id=contacts" },
];

ContactMainListWidgetHelper.prototype = {
    initialize: function (options) {
        this.transactionId = options.transactionId || gs.generateGUID();
        this.logger = new Logger({
            transactionId: this.transactionId,
            source: "ContactMainListWidgetHelper",
            includeTimeStamp: true,
            includeUserInfo: true,
            includeSessionId: true,
        });
    },

    getTableConfigObject: function (params) {
        try {
            return {
                table: "sys_user",
                static_query: "active=true",
                show_new_record_button: "true",
                page_title: "Contacts",
                order_by: "user_name",
                order_direction: "ASC",
                limit: "10",
                can_save_preferences: "true",
                fields_preference_name: "scm_portal.contacts.fields",
                order_by_preference_name: "scm_portal.contacts.order_by",
                order_direction_preference_name:
                    "scm_portal.contacts.order_direction",
                limit_preference_name: "scm_portal.contacts.limit",
                detail_view_page: "contact_details",
                columns: [
                    {
                        label: "User ID",
                        name: "user_name",
                        default: true,
                    },
                    {
                        label: "First name",
                        name: "first_name",
                        default: true,
                    },
                    {
                        label: "Last name",
                        name: "last_name",
                        default: true,
                    },
                    {
                        label: "Email",
                        name: "email",
                        default: true,
                    },
                    {
                        label: "Business Phone",
                        name: "phone",
                    },
                    {
                        label: "Title",
                        name: "title",
                        default: true,
                    },
                    {
                        label: "Department",
                        name: "department",
                    },
                    {
                        label: "Company",
                        name: "company",
                    },
                    {
                        label: "Manager",
                        name: "manager",
                    },
                ],
                can_filter: "true",
                id_field: "user_name",
                filter_fields: [
                    {
                        field: "department",
                        label: "Department",
                        type: "reference",
                        referenceTable: "cmn_department",
                        displayFields: "name;id",
                        displayField: "name",
                        searchFields: "name;id",
                        referenceQualifier: "nameISNOTEMPTY^idISNOTEMPTY",
                        placeholder: "Select a department",
                        pageSize: "10",
                        minimumInputLength: "2",
                        orderBy: "name",
                        orderDirection: "desc",
                    },
                ],
                breadcrumbs:
                    ContactMainListWidgetHelper.CONTACT_MAIN_LIST_BREADCRUMB,
            };
        } catch (error) {
            this.logger.error({
                method: "getTableConfigObject",
                error: error.message,
                params: params,
            });
            throw error;
        }
    },
    type: "ContactMainListWidgetHelper",
};
